#include <stdio.h>
#include <string.h>

int main() {
    int score = 78;
    char grade[3];

    if (score >= 90) {
        strcpy(grade, "AA");
    } else if (score >= 70) {
        strcpy(grade, "BA");
    } else if (score >= 50) {
        strcpy(grade, "CC");
    } else {
        strcpy(grade, "FF");
    }

    printf("Not: %d -> Harf notu: %s\n", score, grade);

    // Switch ornegi
    int day = 3;
    char dayName[12];

    switch (day) {
        case 1:
            strcpy(dayName, "Pazartesi");
            break;
        case 2:
            strcpy(dayName, "Sali");
            break;
        case 3:
            strcpy(dayName, "Carsamba");
            break;
        default:
            strcpy(dayName, "Bilinmeyen");
            break;
    }

    printf("Gun: %s\n", dayName);

    // Ternary operator
    int number = 7;
    printf("%d sayisi %s\n", number, (number % 2 == 0) ? "Cift" : "Tek");

    return 0;
}
